pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract Crowdsale is Ownable, ReentrancyGuard {
    enum State { Active, Paused }

    IERC20 public token;
    IERC20 public usdt;
    uint256 public endTime;
    uint256 public rate; // Rate in tokens per 1 ETH or 1 USDT
    address public outputWallet;
    State public state = State.Active;

    event TokenPurchase(address indexed purchaser, uint256 value, uint256 amount);
    event OutputWalletUpdate(address indexed newOutputWallet);

    modifier onlyWhileActive() {
        require(state == State.Active, "Sale is not active");
        _;
    }

    modifier onlyWhilePaused() {
        require(state == State.Paused, "Sale is not paused");
        _;
    }

    constructor(
        address _token,
        address _usdt,
        uint256 _endTime,
        uint256 _rate,
        address _outputWallet
    ) {
        token = IERC20(_token);
        usdt = IERC20(_usdt);
        endTime = _endTime;
        rate = _rate;
        outputWallet = _outputWallet;
    }

    function buyTokensWithETH() external payable nonReentrant onlyWhileActive {
        require(block.timestamp < endTime, "Sale has ended");
        uint256 ethAmount = msg.value;
        uint256 tokenAmount = ethAmount * rate;
        require(usdt.transferFrom(msg.sender, outputWallet, ethAmount), "Transfer failed");
        deliverTokens(msg.sender, tokenAmount);
        emit TokenPurchase(msg.sender, ethAmount, tokenAmount);
    }

    function buyTokensWithUSDT(uint256 usdtAmount) external nonReentrant onlyWhileActive {
        require(block.timestamp < endTime, "Sale has ended");
        require(usdtAmount > 0, "USDT amount must be greater than zero");
        require(usdt.transferFrom(msg.sender, outputWallet, usdtAmount), "Transfer failed");
        uint256 tokenAmount = usdtAmount * rate;
        deliverTokens(msg.sender, tokenAmount);
        emit TokenPurchase(msg.sender, usdtAmount, tokenAmount);
    }

    function validatePurchase(address purchaser, uint256 ethAmount, uint256 usdtAmount) external view returns (bool) {
        if (block.timestamp >= endTime || state == State.Paused) {
            return false;
        }
        if (ethAmount > 0) {
            return usdt.allowance(purchaser, address(this)) >= ethAmount;
        } else {
            return usdt.allowance(purchaser, address(this)) >= usdtAmount;
        }
    }

    function deliverTokens(address recipient, uint256 amount) internal nonReentrant {
        require(token.transfer(recipient, amount), "Failed to transfer tokens");
    }

    function pauseSale() external onlyOwner {
        require(state == State.Active, "Already paused");
        state = State.Paused;
    }

    function unpauseSale() external onlyOwner {
        require(state == State.Paused, "Already active");
        state = State.Active;
    }

    function updateOutputWallet(address newOutputWallet) external onlyOwner {
        outputWallet = newOutputWallet;
        emit OutputWalletUpdate(newOutputWallet);
    }
